import {apiRequest} from './apiClient';

export type StoryStatus = 'ongoing' | 'completed' | 'hiatus' | string;
export type StoryPrivacy = 'public' | 'private' | string;

export type StoryItem = {
  id: string;
  title: string;
  description?: string | null;
  status?: StoryStatus;
  privacy?: StoryPrivacy;
  tags?: string[];
  cover_url?: string | null;
  vote_count?: number;
  read_count?: number;
  has_voted?: boolean;
  in_library?: boolean;
  created_at?: string;
  updated_at?: string;
  users?: {
    id?: string;
    name?: string;
    username?: string;
    image_url?: string;
  } | null;
  chapters?: StoryChapterSummary[];
  reading_progress?: {
    chapter_id?: string;
    scroll_position?: number;
  } | null;
};

export type StoryChapterSummary = {
  id: string;
  title: string;
  chapter_number?: number;
  status?: 'draft' | 'published' | string;
  word_count?: number;
};

export type StoryChapter = StoryChapterSummary & {
  content?: string | object | null;
  prev_chapter?: StoryChapterSummary | null;
  next_chapter?: StoryChapterSummary | null;
};

export type StoryListResponse = {
  data: StoryItem[];
  hasMore?: boolean;
};

const authHeaders = (token?: string): Record<string, string> => {
  if (!token) {
    return {};
  }
  return {Authorization: `Bearer ${token}`};
};

const appendBeforeLimit = (
  params: URLSearchParams,
  limit: number,
  before?: string | null,
) => {
  params.set('limit', String(limit));
  if (before) {
    params.set('before', before);
  }
};

export const storyApi = {
  async getStories(
    options: {
      limit?: number;
      before?: string | null;
      status?: StoryStatus | null;
      tag?: string | null;
      token?: string;
    } = {},
  ): Promise<StoryListResponse> {
    const params = new URLSearchParams();
    appendBeforeLimit(params, options.limit ?? 10, options.before);
    if (options.status) {
      params.set('status', options.status);
    }
    if (options.tag) {
      params.set('tag', options.tag);
    }

    return apiRequest<StoryListResponse>(`/stories?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(options.token),
      },
    });
  },

  async getStoryById(storyId: string, token?: string): Promise<StoryItem> {
    return apiRequest<StoryItem>(`/stories/${encodeURIComponent(storyId)}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async getMyStories(
    token: string,
    options: {limit?: number; before?: string | null} = {},
  ): Promise<StoryListResponse> {
    const params = new URLSearchParams();
    appendBeforeLimit(params, options.limit ?? 10, options.before);
    return apiRequest<StoryListResponse>(`/stories/my?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async getMyLibrary(
    token: string,
    options: {limit?: number; before?: string | null} = {},
  ): Promise<StoryListResponse> {
    const params = new URLSearchParams();
    appendBeforeLimit(params, options.limit ?? 10, options.before);
    return apiRequest<StoryListResponse>(`/stories/library?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async getUserStories(
    userId: string,
    token?: string,
    options: {limit?: number; before?: string | null} = {},
  ): Promise<StoryListResponse> {
    const params = new URLSearchParams();
    appendBeforeLimit(params, options.limit ?? 10, options.before);
    return apiRequest<StoryListResponse>(
      `/stories/user/${encodeURIComponent(userId)}?${params.toString()}`,
      {
        method: 'GET',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async createStory(
    token: string,
    payload: {
      title: string;
      description?: string;
      status?: StoryStatus;
      privacy?: StoryPrivacy;
      tags?: string[];
      coverImageUri?: string | null;
      coverMimeType?: string;
      coverFileName?: string;
    },
  ): Promise<StoryItem> {
    const formData = new FormData();
    formData.append('title', payload.title.trim());
    formData.append('description', payload.description?.trim() ?? '');
    formData.append('status', payload.status ?? 'ongoing');
    formData.append('privacy', payload.privacy ?? 'public');
    formData.append('tags', JSON.stringify(payload.tags ?? []));

    if (payload.coverImageUri) {
      formData.append('image', {
        uri: payload.coverImageUri,
        type: payload.coverMimeType ?? 'image/jpeg',
        name: payload.coverFileName ?? 'story-cover.jpg',
      } as never);
    }

    return apiRequest<StoryItem>('/stories', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
      },
      body: formData,
    });
  },

  async updateStory(
    token: string,
    storyId: string,
    payload: {
      title: string;
      description?: string;
      status?: StoryStatus;
      privacy?: StoryPrivacy;
      tags?: string[];
      coverImageUri?: string | null;
      coverMimeType?: string;
      coverFileName?: string;
    },
  ): Promise<StoryItem> {
    const formData = new FormData();
    formData.append('title', payload.title.trim());
    formData.append('description', payload.description?.trim() ?? '');
    formData.append('status', payload.status ?? 'ongoing');
    formData.append('privacy', payload.privacy ?? 'public');
    formData.append('tags', JSON.stringify(payload.tags ?? []));

    if (payload.coverImageUri) {
      formData.append('image', {
        uri: payload.coverImageUri,
        type: payload.coverMimeType ?? 'image/jpeg',
        name: payload.coverFileName ?? 'story-cover.jpg',
      } as never);
    }

    return apiRequest<StoryItem>(`/stories/${encodeURIComponent(storyId)}`, {
      method: 'PATCH',
      headers: {
        ...authHeaders(token),
      },
      body: formData,
    });
  },

  async deleteStory(token: string, storyId: string): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(`/stories/${encodeURIComponent(storyId)}`, {
      method: 'DELETE',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async createChapter(
    token: string,
    storyId: string,
    title: string,
  ): Promise<StoryChapter> {
    return apiRequest<StoryChapter>(`/stories/${encodeURIComponent(storyId)}/chapters`, {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({title}),
    });
  },

  async getChapter(
    storyId: string,
    chapterId: string,
    token?: string,
  ): Promise<StoryChapter> {
    return apiRequest<StoryChapter>(
      `/stories/${encodeURIComponent(storyId)}/chapters/${encodeURIComponent(chapterId)}`,
      {
        method: 'GET',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async updateChapter(
    token: string,
    storyId: string,
    chapterId: string,
    payload: {
      title?: string;
      content?: string;
      status?: 'draft' | 'published' | string;
    },
  ): Promise<StoryChapter> {
    return apiRequest<StoryChapter>(
      `/stories/${encodeURIComponent(storyId)}/chapters/${encodeURIComponent(chapterId)}`,
      {
        method: 'PATCH',
        headers: {
          ...authHeaders(token),
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      },
    );
  },

  async deleteChapter(
    token: string,
    storyId: string,
    chapterId: string,
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(
      `/stories/${encodeURIComponent(storyId)}/chapters/${encodeURIComponent(chapterId)}`,
      {
        method: 'DELETE',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async reorderChapters(
    token: string,
    storyId: string,
    chapterOrder: string[],
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(
      `/stories/${encodeURIComponent(storyId)}/chapters/reorder`,
      {
        method: 'POST',
        headers: {
          ...authHeaders(token),
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({chapterOrder}),
      },
    );
  },

  async toggleVote(token: string, storyId: string): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(`/stories/${encodeURIComponent(storyId)}/vote`, {
      method: 'POST',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async toggleLibrary(token: string, storyId: string): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(
      `/stories/${encodeURIComponent(storyId)}/library`,
      {
        method: 'POST',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async getChapterComments(
    chapterId: string,
    paragraphIndex?: number | null,
    token?: string,
  ): Promise<{data?: unknown[]}> {
    const params = new URLSearchParams();
    if (paragraphIndex !== null && paragraphIndex !== undefined) {
      params.set('paragraph_index', String(paragraphIndex));
    }

    const suffix = params.toString() ? `?${params.toString()}` : '';
    return apiRequest<{data?: unknown[]}>(
      `/chapters/${encodeURIComponent(chapterId)}/comments${suffix}`,
      {
        method: 'GET',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async getChapterCommentCounts(
    chapterId: string,
    token?: string,
  ): Promise<{data?: unknown}> {
    return apiRequest<{data?: unknown}>(
      `/chapters/${encodeURIComponent(chapterId)}/comment-counts`,
      {
        method: 'GET',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },

  async addChapterComment(
    token: string,
    chapterId: string,
    payload: unknown,
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(
      `/chapters/${encodeURIComponent(chapterId)}/comments`,
      {
        method: 'POST',
        headers: {
          ...authHeaders(token),
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload ?? {}),
      },
    );
  },

  async saveReadingProgress(
    token: string,
    storyId: string,
    chapterId: string,
    scrollPosition: number,
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>(
      `/stories/${encodeURIComponent(storyId)}/progress`,
      {
        method: 'POST',
        headers: {
          ...authHeaders(token),
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          chapter_id: chapterId,
          scroll_position: scrollPosition,
        }),
      },
    );
  },

  async getReadingProgress(
    token: string,
    storyId: string,
  ): Promise<{chapter_id?: string; scroll_position?: number}> {
    return apiRequest<{chapter_id?: string; scroll_position?: number}>(
      `/stories/${encodeURIComponent(storyId)}/progress`,
      {
        method: 'GET',
        headers: {
          ...authHeaders(token),
        },
      },
    );
  },
};

