 33→export function PostCard({
 34→  title,
 35→  bodyPreview,
 36→  authorName,
 37→  authorAvatar,
 38→  authorBadge,
 39→  bannerImage,
 40→  postType,
 41→  readingTime,
 42→  likeCount,
 43→  commentCount,
 44→  bookmarkCount,
 45→  isLiked,
 46→  isBookmarked,
 47→  userReaction,
 48→  onPress,
 49→  onLike,
 50→  onComment,
 51→  onBookmark,
 52→  onRepost,
 53→  onReact,
 54→}: PostCardProps) {
 55→  const {colors} = useTheme();
 56→  const s = shadows(colors);
 57→
 58→  return (
 59→    <Pressable
 60→      onPress={onPress}
 61→      style={({pressed}) => [
 62→        styles.card,
 63→        {
 64→          backgroundColor: colors.bgCard,
 65→          borderColor: colors.borderCard,
 66→        },
 67→        s.card,
 68→        pressed && styles.pressed,
 69→      ]}>
