 81→          <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
 82→          <Text
 83→            style={[styles.authorName, {color: colors.textSecondary}]}
 84→            numberOfLines={1}>
 85→            {authorName}
 86→          </Text>
 87→          {authorBadge ? <BadgeCheckIcon size={14} badge={authorBadge} /> : null}
 88→          {postType && postType !== 'journal' ? (
 89→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
 90→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
 91→                {postType}
 92→              </Text>
 93→            </View>
 94→          ) : null}
 95→          {readingTime ? (
 96→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
 97→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
 98→                {readingTime}
 99→              </Text>
100→            </View>
101→          ) : null}
102→        </View>
103→
104→        {/* Title */}
105→        <Text
106→          style={[styles.title, {color: colors.textHeading}]}
107→          numberOfLines={2}>
108→          {title}
109→        </Text>
110→
111→        {/* Body preview */}
112→        {bodyPreview ? (
113→          <Text
114→            style={[styles.body, {color: colors.textBody}]}
115→            numberOfLines={3}>
116→            {bodyPreview}
117→          </Text>
118→        ) : null}
119→      </View>
120→
121→      <ActionBar
122→        likeCount={likeCount}
123→        commentCount={commentCount}
124→        bookmarkCount={bookmarkCount}
125→        isLiked={isLiked}
126→        isBookmarked={isBookmarked}
127→        userReaction={userReaction}
128→        onLike={onLike}
129→        onComment={onComment}
130→        onBookmark={onBookmark}
131→        onRepost={onRepost}
132→        onReact={onReact}
133→      />
134→    </Pressable>
135→  );
136→}
