import React from 'react';
import {Image, Pressable, StyleSheet, Text, View} from 'react-native';
import {GlassCard} from '../../components/GlassCard';
import {HeartIcon, BookIcon} from '../../components/icons';
import {useTheme} from '../../theme/ThemeProvider';
import {fonts} from '../../theme/typography';
import {spacing, radii} from '../../theme/spacing';
import type {StoryItem} from '../../lib/api/storyApi';

interface ProfileStoryCardProps {
  story: StoryItem;
  onPress: () => void;
}

const STATUS_COLORS: Record<string, {bg: string; text: string}> = {
  ongoing: {bg: 'rgba(34,197,94,0.12)', text: '#22C55E'},
  completed: {bg: 'rgba(168,85,247,0.12)', text: '#A855F7'},
  hiatus: {bg: 'rgba(249,115,22,0.12)', text: '#F97316'},
};

export function ProfileStoryCard({story, onPress}: ProfileStoryCardProps) {
  const {colors} = useTheme();
  const statusStyle = STATUS_COLORS[story.status ?? ''] ?? STATUS_COLORS.ongoing;

  return (
    <Pressable onPress={onPress}>
      <GlassCard style={styles.card}>
        {story.cover_url ? (
          <Image
            source={{uri: story.cover_url}}
            style={styles.cover}
            resizeMode="cover"
          />
        ) : (
          <View style={[styles.coverPlaceholder, {backgroundColor: colors.bgSecondary}]}>
            <BookIcon size={32} color={colors.textMuted} />
          </View>
        )}

        <View style={styles.body}>
          <Text
            style={[styles.title, {color: colors.textHeading}]}
            numberOfLines={2}>
            {story.title}
          </Text>

          {story.description ? (
            <Text
              style={[styles.description, {color: colors.textSecondary}]}
              numberOfLines={2}>
              {story.description}
            </Text>
          ) : null}

          <View style={styles.metaRow}>
            {story.status ? (
              <View
                style={[
                  styles.statusBadge,
                  {backgroundColor: statusStyle.bg},
                ]}>
                <Text style={[styles.statusText, {color: statusStyle.text}]}>
                  {story.status.charAt(0).toUpperCase() + story.status.slice(1)}
                </Text>
              </View>
            ) : null}

            {story.tags && story.tags.length > 0 ? (
              <View style={styles.tagsRow}>
                {story.tags.slice(0, 2).map(tag => (
                  <View
                    key={tag}
                    style={[styles.tag, {backgroundColor: colors.bgSecondary}]}>
                    <Text style={[styles.tagText, {color: colors.textMuted}]}>
                      {tag}
                    </Text>
                  </View>
                ))}
              </View>
            ) : null}
