            <View style={styles.statItem}>
              <HeartIcon size={14} color={colors.textMuted} />
              <Text style={[styles.statText, {color: colors.textMuted}]}>
                {story.vote_count ?? 0}
              </Text>
            </View>
            <View style={styles.statItem}>
              <BookIcon size={14} color={colors.textMuted} />
              <Text style={[styles.statText, {color: colors.textMuted}]}>
                {story.read_count ?? 0}
