        if (query.hasNextPage && !query.isFetchingNextPage) {
          query.fetchNextPage();
        }
      }}
      ListEmptyComponent={
        query.isLoading ? (
          <View style={styles.skeletons}>
            <PostCardSkeleton />
            <PostCardSkeleton />
          </View>
