 19→const PAGE_SIZE = 10;
 20→
 21→interface ProfileWritingsTabProps {
 22→  userId: string;
 23→  headerComponent?: React.ReactElement;
 24→}
 25→
 26→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 27→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 28→
 29→  const query = useInfiniteQuery({
 30→    queryKey: ['profileWritings', userId],
 31→    queryFn: ({pageParam}) =>
 32→      mobileApi.getUserJournals(userId, pageParam ?? null, PAGE_SIZE),
 33→    initialPageParam: null as string | null,
 34→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 35→  });
 36→
 37→  const posts = useMemo(
 38→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
 39→    [query.data?.pages],
 40→  );
 41→
 42→  return (
 43→    <FlatList
 44→      data={posts}
 45→      keyExtractor={item => item.id}
 46→      showsVerticalScrollIndicator={false}
 47→      contentContainerStyle={styles.list}
 48→      ListHeaderComponent={headerComponent}
 49→      onEndReachedThreshold={0.3}
 50→      onEndReached={() => {
 51→        if (query.hasNextPage && !query.isFetchingNextPage) {
 52→          query.fetchNextPage();
 53→        }
 54→      }}
 55→      ListEmptyComponent={
 56→        query.isLoading ? (
 57→          <View style={styles.skeletons}>
 58→            <PostCardSkeleton />
 59→            <PostCardSkeleton />
 60→            <PostCardSkeleton />
 61→          </View>
 62→        ) : (
 63→          <EmptyState
 64→            title="No writings yet"
 65→            subtitle="Journal posts will appear here."
 66→          />
 67→        )
 68→      }
 69→      ListFooterComponent={
 70→        query.isFetchingNextPage ? (
 71→          <View style={styles.footer}>
 72→            <PostCardSkeleton />
 73→          </View>
 74→        ) : null
 75→      }
 76→      renderItem={({item}) => {
 77→        const preview = extractPlainText(item.content).slice(0, 180);
 78→        const likeCount = resolveCount(item.like_count, item.likes_count);
 79→        const commentCount = resolveCount(item.comment_count, item.comments_count);
 80→        const bookmarkCount = resolveCount(item.bookmark_count);
 81→        const bannerImage = extractBannerImage(item.content, (item as any).images);
 82→
 83→        return (
 84→          <PostCard
 85→            title={item.title || 'Untitled Post'}
 86→            bodyPreview={preview || 'No preview text available.'}
 87→            authorName={item.users?.name || 'Unknown author'}
 88→            authorAvatar={item.users?.image_url}
 89→            authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
 90→            bannerImage={bannerImage}
 91→            postType={item.post_type ?? undefined}
 92→            likeCount={likeCount}
 93→            commentCount={commentCount}
 94→            bookmarkCount={bookmarkCount}
 95→            userReaction={item.user_reaction}
 96→            onPress={() =>
 97→              navigation.navigate('PostDetail', {journalId: item.id})
 98→            }
 99→          />
100→        );
101→      }}
102→      ItemSeparatorComponent={() => <View style={styles.separator} />}
103→    />
104→  );
105→}
