740→    const {data, error} = await query;
741→
742→    if(error){
743→        console.error('supabase error while fetching journals:', error.message);
744→        throw{status: 500, error: 'supabase error while fetching journals'}
745→    }
746→
747→    if(data.length === 0){
748→        const journalData = {
749→            data: [],
750→            hasMore: false
751→        }
752→        return journalData
753→    }
754→
755→    // If userId is provided, fetch personalization (likes/bookmarks/reactions)
756→    // Otherwise return journals with has_liked/has_bookmarked/user_reaction defaulting to false/null
757→    let userHasLikedSet = new Set();
758→    let userHasBookmarkedSet = new Set();
759→    let userReactionMap = new Map();
760→
761→    if(userId){
762→        const journalIds = data.map((journal) => journal.id);
763→
764→        const [userLikes, userBookmarks, userReactions] = await Promise.all([
765→            supabase
766→            .from('likes')
767→            .select('journal_id')
768→            .in('journal_id', journalIds)
769→            .eq('user_id', userId),
770→
771→            supabase
772→            .from('bookmarks')
773→            .select('journal_id')
774→            .in('journal_id', journalIds)
775→            .eq('user_id', userId),
776→
777→            supabase
778→            .from('reactions')
779→            .select('journal_id, reaction_type')
780→            .in('journal_id', journalIds)
781→            .eq('user_id', userId)
782→        ]);
783→
784→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
785→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
786→        const {data: userReactionsResult} = userReactions;
787→
788→        if(errorUserLikeResult || errorUserBookmarksResult) {
789→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
790→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
791→        }
792→
793→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
794→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
795→        userReactionMap = new Map((userReactionsResult || []).map((r) => [r.journal_id, r.reaction_type]));
796→    }
797→
798→    await attachRepostSources(data);
